INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQBKZJRY3PMWV07MAVKEV', 'Sittax Simples', 'sittax-simples', NULL, 'A Sittax Simples é uma solução SaaS robusta projetada para modernizar o departamento fiscal de empresas do Simples Nacional. Simplifica a gestão tributária ao automatizar a análise de notas fiscais, a segregação de tributos como Monofásico e ST, e a transmissão de dados para o portal oficial. Além disso, a ferramenta agiliza a geração de Guias DAS, relatórios de auditoria e o envio de informações críticas aos empresários, integrando-se perfeitamente ao software contábil do contador para uma eficiência operacional sem precedentes.', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=Sittax%20Simples', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:03.585+00', '2026-05-15 12:28:03.585+00', NULL, NULL) ON CONFLICT DO NOTHING;
