INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQC07HDVW24JB2KFD1YQE', 'Busca Legal T2', 'busca-legal-t2', NULL, 'Já pensou em abrir a tela de seu computador e perguntar qual é a tributação de um produto, tanto em operações internas quanto interestaduais? Pois é, isso já é possível com o Busca.Legal T2, seu Assistente Pessoal Tributário! E se você tiver a NCM ou o Código de Barras desse produto, fica mais fácil ainda!', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=Busca%20Legal%20T2', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:03.976+00', '2026-05-15 12:28:03.976+00', NULL, NULL) ON CONFLICT DO NOTHING;
