INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQD2Z35FGX5WKDJNBC29A', 'LINC - Gestão Inteligente de Investimentos Sociais', 'linc-gestao-inteligente-de-investimentos-sociais', NULL, 'A LINC é uma plataforma desenvolvida para facilitar a gestão de projetos incentivados por leis de incentivo fiscal. Com uma interface intuitiva e funcionalidades estratégicas, a plataforma permite que empresas acompanhem o andamento dos projetos que apoiam e visualizem indicadores de impacto e conformidade.', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=LINC%20-%20Gest%C3%A3o%20Inteligente%20de%20I', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:05.087+00', '2026-05-15 12:28:05.087+00', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQD5HW64MPF9QNRCZNG08', 'Reforma Tributária', 'reforma-tributaria', NULL, 'O ambiente oferece uma visão clara e estruturada dos impactos fiscais, permitindo simulações de cenários, parametrização de alíquotas e análise detalhada por item, fornecedor e cliente. 
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQDFXQBMC9TZVDWSD6XYK', 'Strategy', 'strategy', NULL, 'O ROIT Strategy é um sistema de inteligência tributária projetado para orquestrar a operação real da Reforma Tributária, indo além da simples simulação para conectar dados, decisões e execução integrada. Ele realiza um diagnóstico profundo da operação, expondo impactos tributários de forma granular , item a item e fornecedor a fornecedor, enquanto antecipa efeitos no capital de giro e fluxo de caixa ao longo dos anos', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=Strategy', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:05.501+00', '2026-05-15 12:28:05.501+00', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQDKQRTQ6ERP4JAKZS8BT', 'Conta-Corrente Fiscal', 'conta-corrente-fiscal', NULL, 'Módulo voltado a consolidar e “estruturar” a conta-corrente fiscal (situação de débitos, pendências e inconsistências) mediante a consulta recorrente do relatório/extrato de débitos e sua transformação em um arquivo com formato acionável (para Excel). A proposta é sair do PDF/consulta manual sem abrir mão da sua manutenção em histórico, e transformar em dados organizados para priorização, acompanhamento e atuação rápida do time (ex.: o que é risco, o que é divergência, o que exige ação).', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=Conta-Corrente%20Fiscal', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:05.623+00', '2026-05-15 12:28:05.623+00', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQCHNGY2WR10TNQRT9NND', 'V360', 'v360', NULL, 'O V360 começa pela captura multicanal e leitura inteligente de notas fiscais, pronta para os novos campos da Reforma Tributária. A partir daí, aplica validações totalmente customizáveis, com regras de negócio no code que podem ser configuradas do zero, além de workflows automáticos de tratativa para qualquer divergência. Assim, já automatizamos milhares de tarefas manuais e liberamos as maiores empresas do Brasil para focar no que fazem melhor: crescer. Com a complexidade da Reforma, nosso papel é ainda mais estratégico — simplificar o impossível e transformar sua esteira de pagamentos em vantagem competitiva.', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=V360', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:04.534+00', '2026-05-15 12:28:04.534+00', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQCKYQFWCW178RPVBX8PE', 'Full Tax Service', 'full-tax-service', NULL, 'No escritório Menndel & Melo Advocacia oferecemos uma solução completa em consultoria, controladoria e gestão fiscal e tributária com nosso serviço Full Tax Service.', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=Full%20Tax%20Service', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:04.606+00', '2026-05-15 12:28:04.606+00', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQCPPGZN4JY1WGHSD86EA', 'Conta Digital Empresarial Logisbank', 'conta-digital-empresarial-logisbank', NULL, 'A Conta Digital Empresarial Logisbank é uma solução completa para empresas que buscam praticidade, segurança e autonomia na gestão financeira. Permite realizar transferências (Pix, TED, boletos), acompanhar o fluxo de caixa e centralizar operações bancárias em uma plataforma simples e eficiente — mesmo para negócios com restrições financeiras.', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=Conta%20Digital%20Empresarial%20Logi', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:04.694+00', '2026-05-15 12:28:04.694+00', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQCRX9WWGTW4C4Z23K39T', 'Educação e Mentoria Tributária', 'educacao-e-mentoria-tributaria', NULL, 'A Tributariou Educational Services desenvolve programas educacionais e mentorias voltadas à formação de profissionais e empresas na nova era tributária. A metodologia é prática, atualizada e baseada em dados reais, com foco na Reforma Tributária e em estratégias de precificação e gestão fiscal.', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=Educa%C3%A7%C3%A3o%20e%20Mentoria%20Tribut%C3%A1ria', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:04.766+00', '2026-05-15 12:28:04.766+00', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQCV7SDMMW41HRB61RVYT', 'Consultoria Tributária Especializada', 'consultoria-tributaria-especializada', NULL, 'A Tributariou Business Consulting oferece consultoria completa para adequação à Reforma Tributária (LC 214/2025), com foco em diagnóstico, revisão fiscal, conformidade e planejamento estratégico. O serviço alia técnica jurídica e inteligência de negócios para transformar a complexidade tributária em vantagem competitiva.', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=Consultoria%20Tribut%C3%A1ria%20Especia', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:04.839+00', '2026-05-15 12:28:04.839+00', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQCXS53KYEYF194BZQ4RF', 'Total Inbound', 'total-inbound', NULL, 'O SAP TOTAL INBOUND é um produto que garante o recebimento dos XML’s no ERP SAP, automatizando o processo de entrada física e fiscal de mercadorias, CTe, serviços e outros documentos.
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQD18WP92YPY9EGFKQATZ', 'Monitor', 'monitor', NULL, 'Plataforma para gestão integrada de documentos fiscais e certidões.
