INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQD72GB26BCJVS0X19YG1', 'Gerenciador de Certidões', 'gerenciador-de-certidoes', NULL, 'Módulo para automatizar a consulta e renovação de mais de 200 tipos de certidões (federais, estaduais, municipais e outras), centralizando tudo em um único lugar. 
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQDHW0CVX1MKVVWRZ2Y5T', 'Tax Transformation as a Service (Projetos Customizáveis)', 'tax-transformation-as-a-service-projetos-customizaveis', NULL, 'A frente de “Tax Transformation as a Service” (ou projetos de customização) na Taxly é, na prática, quando a gente combina a plataforma (SaaS) com um modelo de projeto para desenhar, adaptar e implementar fluxos específicos do cliente — indo além do “módulo padrão”. Normalmente envolve: discovery do processo atual, prototipação/definição funcional, especificação técnica, configuração/parametrizações, integração ou automação sob medida, homologação e operação assistida (com rituais e acompanhamento)
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQDQYEWA41104P4GRCXXF', 'Caixa Postal Fiscal (DTE)', 'caixa-postal-fiscal-dte', NULL, 'O módulo/produto de Caixa Postal Fiscal (DTE/DEC) da Taxly centraliza e automatiza o monitoramento das comunicações oficiais (intimações, notificações e avisos) que chegam nas “caixas postais” dos órgãos fiscais (ex.: e-CAC/Receita Federal e DTEs estaduais). A ideia é tirar o time do fluxo manual de “logar CNPJ por CNPJ” e "acessar caixa de e-mail por caixa de e-mail), reduzir risco de ciência tácita/perda de prazo e dar governança sobre o que chegou, quando, quem abriu/deu ciência e como foi tratado.', false, 'published', 'https://placehold.co/600x400/2563eb/ffffff?text=Caixa%20Postal%20Fiscal%20(DTE)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:05.759+00', '2026-05-15 12:28:05.759+00', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.product (id, title, handle, subtitle, description, is_giftcard, status, thumbnail, weight, length, height, width, origin_country, hs_code, mid_code, material, collection_id, type_id, discountable, external_id, created_at, updated_at, deleted_at, metadata) VALUES ('prod_01KRNSQC5JETE0XT40GVX19BRW', 'Tax True', 'tax-true', NULL, 'O TAX TRUE é uma solução tecnológica da ROIT voltada à conciliação das apurações assistidas. Ele valida as informações fiscais através da conferência sistemática entre cinco bases de dados: os documentos fiscais eletrônicos (DF-e), a Receita Federal, o Comitê Gestor do IBS, o ERP e o extrato bancário.', false, 'published', 'http://localhost:9100/medusa-media/image_wDG60WCaptura de tela 2026-03-02 124216 (1)-01KRV2NXK7WV6S8KEJ49TWCSHV.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, true, NULL, '2026-05-15 12:28:04.147+00', '2026-05-17 13:40:45.903+00', NULL, NULL) ON CONFLICT DO NOTHING;
