INSERT INTO public.seller (id, name, handle, description, photo, created_at, updated_at, deleted_at, address_line, city, postal_code, country_code, tax_id, email, phone, state, store_status) VALUES ('sel_01KRNSQAH2RCD5Z8XABC5ZF05J', 'V360', 'v360', 'A V360 é a plataforma que elimina tarefas manuais no processo de pagamento a fornecedores — da captura da nota fiscal à integração com o ERP — garantindo compliance e eficiência, mesmo em cenários complexos como a Reforma Tributária.', 'https://api.findtax.com.br/api/v1/asset/img/image_iGsaKJprovider-logo.png', '2026-05-15 12:28:02.466+00', '2026-05-15 12:28:02.466+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE') ON CONFLICT DO NOTHING;
INSERT INTO public.seller (id, name, handle, description, photo, created_at, updated_at, deleted_at, address_line, city, postal_code, country_code, tax_id, email, phone, state, store_status) VALUES ('sel_01KRNSQAXSJYEE618G1MJAV2Y7', 'LogisBank', 'logisbank', 'A Logisbank é uma fintech especializada em soluções bancárias digitais voltadas exclusivamente para empresas. Oferecemos conta digital empresarial, gestão financeira completa, emissão de boletos e crédito corporativo, inclusive para empresas com restrições. Nosso propósito é simplificar o acesso a serviços financeiros e impulsionar o crescimento de negócios por meio de tecnologia, transparência e atendimento humano.', 'https://api.findtax.com.br/api/v1/asset/img/image_xb4cB9provider-logo.png', '2026-05-15 12:28:02.873+00', '2026-05-15 12:28:02.873+00', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'ACTIVE') ON CONFLICT DO NOTHING;
