INSERT INTO public.seller (id, name, handle, description, photo, created_at, updated_at, deleted_at, address_line, city, postal_code, country_code, tax_id, email, phone, state, store_status) VALUES ('sel_01KRNSQ934TWSRM5J5AKS01SEQ', 'ROIT', 'roit', 'A ROIT é um ecossistema completo de soluções para empresas que encaram a Reforma Tributária como uma oportunidade de transformação. Unimos alta tecnologia, inteligência fiscal e consultoria especializada para garantir protagonismo, eficiência e conformidade em um cenário tributário cada vez mais desafiador. Nossa missão é inovar o ecossistema financeiro e tributário e transformá-lo em inteligência de fácil acesso.', 'https://api.findtax.com.br/api/v1/asset/img/image_EJ49jDroit.png', '2026-05-15 12:28:00.996+00', '2026-05-17 13:36:15.718+00', NULL, NULL, NULL, NULL, NULL, NULL, 'roit@findtax.com', '1199999-9999', NULL, 'ACTIVE') ON CONFLICT DO NOTHING;
